-- Migration 006: Import Excel catalog, track structures, awning rates, and product recipes
-- Sources: Excel File/*.xlsx plus New RRP PDF already imported by migration 005

BEGIN;

CREATE TABLE IF NOT EXISTS public.excel_catalog_source_sheets (
  source_file TEXT NOT NULL,
  sheet_name TEXT NOT NULL,
  row_count INTEGER NOT NULL DEFAULT 0,
  column_count INTEGER NOT NULL DEFAULT 0,
  non_empty_row_count INTEGER NOT NULL DEFAULT 0,
  sheet_text TEXT NOT NULL DEFAULT '',
  extracted_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (source_file, sheet_name)
);
ALTER TABLE public.excel_catalog_source_sheets ENABLE ROW LEVEL SECURITY;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.excel_catalog_source_sheets TO authenticated;
DROP POLICY IF EXISTS excel_catalog_source_sheets_read ON public.excel_catalog_source_sheets;
CREATE POLICY excel_catalog_source_sheets_read ON public.excel_catalog_source_sheets FOR SELECT TO authenticated USING (true);
DROP POLICY IF EXISTS excel_catalog_source_sheets_admin_write ON public.excel_catalog_source_sheets;
CREATE POLICY excel_catalog_source_sheets_admin_write ON public.excel_catalog_source_sheets FOR ALL TO authenticated USING (public.current_app_role() = 'admin') WITH CHECK (public.current_app_role() = 'admin');

