CREATE OR REPLACE FUNCTION public.normalize_excel_catalog_seed_name(value TEXT)
RETURNS TEXT LANGUAGE sql IMMUTABLE AS $$
  SELECT lower(regexp_replace(trim(coalesce(value, '')), '\s+', ' ', 'g'));
$$;

CREATE OR REPLACE FUNCTION public.strip_excel_component_prefix(value TEXT)
RETURNS TEXT LANGUAGE plpgsql IMMUTABLE AS $$
DECLARE
  v TEXT := trim(coalesce(value, ''));
  p TEXT;
  prefixes TEXT[] := ARRAY['Curtain Tracks-', 'Roller W/o Headrail-', 'Roller with Headrail-', 'Sheer Dimout Plain Cassette-', 'Sheer Dimout Decorative Cassette-', 'Sheer Dimout Decorative Square Cassette-', 'S-Contour-', 'Roller with Plain Cassette-', 'Roller with Decorative Cassette-', 'Roller with Decorative Square Cassette-', 'Vertical Blinds-', 'Roman Blinds-'];
BEGIN
  FOREACH p IN ARRAY prefixes LOOP
    IF lower(v) LIKE lower(p) || '%' THEN
      RETURN trim(substr(v, length(p) + 1));
    END IF;
  END LOOP;
  RETURN v;
END;
$$;

CREATE OR REPLACE FUNCTION public.ensure_excel_catalog_variant_seed(
  p_category_name TEXT, p_product_name TEXT, p_component_label TEXT, p_unit TEXT DEFAULT 'pcs', p_purchase_rate NUMERIC DEFAULT NULL
) RETURNS UUID LANGUAGE plpgsql AS $$
DECLARE
  v_category_id UUID; v_product_id UUID; v_variant_id UUID;
  v_variant_name TEXT := public.strip_excel_component_prefix(p_component_label);
  v_category_norm TEXT := public.normalize_excel_catalog_seed_name(p_category_name);
  v_product_norm TEXT := public.normalize_excel_catalog_seed_name(p_product_name);
  v_full_norm TEXT := public.normalize_excel_catalog_seed_name(p_component_label);
  v_variant_norm TEXT := public.normalize_excel_catalog_seed_name(v_variant_name);
  v_s_contour_norm TEXT := CASE WHEN lower(trim(coalesce(p_component_label, ''))) LIKE 's-contour-%' THEN public.normalize_excel_catalog_seed_name('Contour-' || v_variant_name) ELSE NULL END;
BEGIN
  INSERT INTO public.inv_categories(name, normalized_name, sub_group) VALUES (trim(p_category_name), v_category_norm, 'Parts')
  ON CONFLICT (normalized_name) DO UPDATE SET name = EXCLUDED.name, sub_group = COALESCE(public.inv_categories.sub_group, EXCLUDED.sub_group) RETURNING id INTO v_category_id;

  SELECT v.id INTO v_variant_id
  FROM public.inv_variants v JOIN public.inv_products p ON p.id = v.product_id
  WHERE p.category_id = v_category_id AND v.normalized_name IN (v_variant_norm, v_full_norm, COALESCE(v_s_contour_norm, v_variant_norm))
  ORDER BY CASE WHEN v.normalized_name = v_variant_norm THEN 0 ELSE 1 END, v.created_at LIMIT 1;
  IF v_variant_id IS NOT NULL THEN
    UPDATE public.inv_variants SET unit = COALESCE(NULLIF(p_unit, ''), unit), purchase_rate = COALESCE(p_purchase_rate, purchase_rate) WHERE id = v_variant_id;
    RETURN v_variant_id;
  END IF;

  INSERT INTO public.inv_products(category_id, name, normalized_name) VALUES (v_category_id, trim(p_product_name), v_product_norm)
  ON CONFLICT (category_id, normalized_name) DO UPDATE SET name = EXCLUDED.name RETURNING id INTO v_product_id;
  INSERT INTO public.inv_variants(product_id, name, normalized_name, unit, purchase_rate) VALUES (v_product_id, v_variant_name, v_variant_norm, COALESCE(NULLIF(p_unit, ''), 'pcs'), p_purchase_rate)
  ON CONFLICT (product_id, normalized_name) DO UPDATE SET name = EXCLUDED.name, unit = EXCLUDED.unit, purchase_rate = COALESCE(EXCLUDED.purchase_rate, public.inv_variants.purchase_rate) RETURNING id INTO v_variant_id;
  RETURN v_variant_id;
END;
$$;

CREATE OR REPLACE FUNCTION public.ensure_excel_product_recipe_seed(p_blind_type TEXT, p_description TEXT DEFAULT NULL)
RETURNS UUID LANGUAGE plpgsql AS $$
DECLARE v_id UUID;
BEGIN
  INSERT INTO public.product_recipes(blind_type, name, description, is_active, notes)
  VALUES (trim(p_blind_type), trim(p_blind_type), p_description, true, 'Imported/updated from Excel catalog migration 006')
  ON CONFLICT (blind_type) DO UPDATE SET name = EXCLUDED.name, description = COALESCE(EXCLUDED.description, public.product_recipes.description), is_active = true, notes = EXCLUDED.notes
  RETURNING id INTO v_id;
  DELETE FROM public.recipe_items WHERE recipe_id = v_id AND notes LIKE '%Excel catalog migration 006%';
  RETURN v_id;
END;
$$;

CREATE OR REPLACE FUNCTION public.seed_excel_recipe_component(
  p_blind_type TEXT, p_category_name TEXT, p_product_name TEXT, p_component_label TEXT, p_quantity NUMERIC, p_is_width_dependent BOOLEAN, p_unit TEXT, p_sort_order INTEGER, p_source_note TEXT
) RETURNS VOID LANGUAGE plpgsql AS $$
DECLARE v_recipe_id UUID; v_variant_id UUID;
BEGIN
  SELECT id INTO v_recipe_id FROM public.product_recipes WHERE blind_type = trim(p_blind_type) LIMIT 1;
  IF v_recipe_id IS NULL THEN v_recipe_id := public.ensure_excel_product_recipe_seed(p_blind_type, 'Auto-created from Excel component catalog'); END IF;
  v_variant_id := public.ensure_excel_catalog_variant_seed(p_category_name, p_product_name, p_component_label, p_unit, NULL);
  INSERT INTO public.recipe_items(recipe_id, variant_id, quantity_per_unit, is_width_dependent, sort_order, component_name, notes)
  VALUES (v_recipe_id, v_variant_id, COALESCE(p_quantity, 0), COALESCE(p_is_width_dependent, false), p_sort_order, trim(p_component_label), trim(coalesce(p_source_note, '')) || ' | Imported from Excel catalog migration 006');
END;
$$;

CREATE OR REPLACE FUNCTION public.import_excel_rrp_entry_seed(p_blind_type TEXT, p_fabric_group TEXT, p_fabric_name TEXT, p_uom TEXT, p_price_map JSONB, p_sort_order INTEGER, p_source_file TEXT, p_source_section TEXT)
RETURNS VOID LANGUAGE plpgsql AS $$
BEGIN
  INSERT INTO public.rrp_entries(blind_type, fabric_group, fabric_name, uom, sort_order, price_map, source_file, source_section)
  VALUES (trim(p_blind_type), trim(p_fabric_group), trim(p_fabric_name), COALESCE(NULLIF(trim(p_uom), ''), 'PC'), p_sort_order, COALESCE(p_price_map, '{}'::jsonb), p_source_file, p_source_section)
  ON CONFLICT (blind_type, fabric_group, fabric_name) DO UPDATE SET uom = EXCLUDED.uom, sort_order = EXCLUDED.sort_order, price_map = EXCLUDED.price_map, source_file = EXCLUDED.source_file, source_section = EXCLUDED.source_section, updated_at = NOW();
END;
$$;

