DO $$
DECLARE
  v_page UUID; v_root UUID; v_group UUID;
BEGIN
  v_page := public.ensure_master_page_seed('Tracks', 20);
  v_root := public.ensure_master_node_seed(NULL, 'Curtain Tracks', FALSE, 0);
  UPDATE public.master_nodes SET page_id = v_page WHERE id = v_root AND page_id IS DISTINCT FROM v_page;
  PERFORM public.ensure_master_node_seed(v_root, 'Super Track', FALSE, 0);
  PERFORM public.ensure_master_node_seed(v_root, 'Jumbo Track', FALSE, 0);
  PERFORM public.ensure_master_node_seed(v_root, 'M Track', FALSE, 0);

  v_page := public.ensure_master_page_seed('Awnings', 40);
  v_root := public.ensure_master_node_seed(NULL, 'Awnings', FALSE, 0);
  UPDATE public.master_nodes SET page_id = v_page WHERE id = v_root AND page_id IS DISTINCT FROM v_page;
  PERFORM public.ensure_master_node_seed(v_root, 'Horizon II', FALSE, 0);
  PERFORM public.ensure_master_node_seed(v_root, 'Horizon III', FALSE, 0);
  PERFORM public.ensure_master_node_seed(v_root, 'Dutch Awning', FALSE, 0);

  v_page := public.ensure_master_page_seed('Rods', 50);
  v_root := public.ensure_master_node_seed(NULL, 'Drapery Rods', FALSE, 0);
  UPDATE public.master_nodes SET page_id = v_page WHERE id = v_root AND page_id IS DISTINCT FROM v_page;
  PERFORM public.ensure_master_node_seed(v_root, 'SS Drapery Rods', FALSE, 0);
  PERFORM public.ensure_master_node_seed(v_root, 'MS Powder Coated Rods', FALSE, 0);
  PERFORM public.ensure_master_node_seed(v_root, 'Soffio Rods', FALSE, 0);
  PERFORM public.ensure_master_node_seed(v_root, 'Heritage Drapery Rods', FALSE, 0);

  v_page := public.ensure_master_page_seed('Flooring', 60);
  v_root := public.ensure_master_node_seed(NULL, 'Wooden Flooring', FALSE, 0);
  UPDATE public.master_nodes SET page_id = v_page WHERE id = v_root AND page_id IS DISTINCT FROM v_page;
  PERFORM public.ensure_master_node_seed(v_root, 'Premium AC-4', FALSE, 0);
  PERFORM public.ensure_master_node_seed(v_root, 'Vintage AC-5', FALSE, 0);
  PERFORM public.ensure_master_node_seed(v_root, 'Classic AC-3', FALSE, 0);
  PERFORM public.ensure_master_node_seed(v_root, 'Chevron', FALSE, 0);
  PERFORM public.ensure_master_node_seed(v_root, 'Engineered Wood Flooring', FALSE, 0);
  PERFORM public.ensure_master_node_seed(v_root, 'Accessories', FALSE, 0);
END;
$$;

